 73ŌåÆ                    }
 74ŌåÆ                    return@ClickableText
 75ŌåÆ                }
 76ŌåÆ
 77ŌåÆ            // Then regular links and hashtags
 78ŌåÆ            annotatedString.getStringAnnotations("URL", offset, offset)
 79ŌåÆ                .firstOrNull()?.let { annotation ->
 80ŌåÆ                    if (onLinkClick != null) {
 81ŌåÆ                        onLinkClick(annotation.item)
 82ŌåÆ                    } else {
