 90ŌåÆ/**
 91ŌåÆ * Extracts a fediverse handle from a mention URL.
 92ŌåÆ * e.g. "https://hackers.pub/@user" -> "user@hackers.pub"
 93ŌåÆ *      "https://mastodon.social/@user" -> "user@mastodon.social"
 94ŌåÆ */
 95ŌåÆprivate fun extractHandleFromUrl(url: String): String? {
 96ŌåÆ    return try {
 97ŌåÆ        val uri = URI(url)
 98ŌåÆ        val host = uri.host ?: return null
 99ŌåÆ        val path = uri.path ?: return null
100ŌåÆ        val username = path.trimStart('/').removePrefix("@")
101ŌåÆ        if (username.isNotEmpty()) "$username@$host" else null
102ŌåÆ    } catch (_: Exception) {
103ŌåÆ        null
104ŌåÆ    }
105ŌåÆ}
