313ŌåÆprivate fun appendStyledText(
314ŌåÆ    builder: AnnotatedString.Builder,
315ŌåÆ    text: String,
316ŌåÆ    linkType: LinkType?,
317ŌåÆ    linkColor: Color,
318ŌåÆ    mentionBg: Color
319ŌåÆ) {
320ŌåÆ    when (linkType) {
321ŌåÆ        LinkType.MENTION -> {
322ŌåÆ            builder.withStyle(
323ŌåÆ                SpanStyle(
324ŌåÆ                    color = linkColor,
325ŌåÆ                    fontWeight = FontWeight.SemiBold,
326ŌåÆ                    background = mentionBg
327ŌåÆ                )
328ŌåÆ            ) {
329ŌåÆ                append(text)
330ŌåÆ            }
331ŌåÆ        }
332ŌåÆ        LinkType.HASHTAG -> {
333ŌåÆ            builder.withStyle(SpanStyle(color = linkColor)) {
334ŌåÆ                append(text)
335ŌåÆ            }
336ŌåÆ        }
337ŌåÆ        LinkType.REGULAR -> {
338ŌåÆ            builder.withStyle(
339ŌåÆ                SpanStyle(
340ŌåÆ                    color = linkColor,
341ŌåÆ                    textDecoration = TextDecoration.Underline
342ŌåÆ                )
343ŌåÆ            ) {
344ŌåÆ                append(text)
345ŌåÆ            }
346ŌåÆ        }
347ŌåÆ        null -> {
348ŌåÆ            builder.append(text)
349ŌåÆ        }
350ŌåÆ    }
351ŌåÆ}
352ŌåÆ
353ŌåÆprivate fun parseAttributes(attrString: String): Map<String, String> {
354ŌåÆ    val attrs = mutableMapOf<String, String>()
355ŌåÆ    for (match in ATTR_REGEX.findAll(attrString)) {
356ŌåÆ        attrs[match.groupValues[1]] = match.groupValues[2]
357ŌåÆ    }
358ŌåÆ    return attrs
359ŌåÆ}
360ŌåÆ
361ŌåÆprivate fun decodeHtmlEntities(text: String): String {
362ŌåÆ    return text
363ŌåÆ        .replace("&nbsp;", " ")
364ŌåÆ        .replace("&amp;", "&")
365ŌåÆ        .replace("&lt;", "<")
366ŌåÆ        .replace("&gt;", ">")
367ŌåÆ        .replace("&quot;", "\"")
368ŌåÆ        .replace("&#39;", "'")
369ŌåÆ        .replace("&apos;", "'")
370ŌåÆ}
