 369ŌåÆ    private func performRelationshipAction(_ action: ActorRelationshipAction, handle: String) {
 370ŌåÆ        guard authManager.isAuthenticated else { return }
 371ŌåÆ        guard !isApplyingRelationshipAction else { return }
 372ŌåÆ
 373ŌåÆ        Task {
 374ŌåÆ            isApplyingRelationshipAction = true
 375ŌåÆ            defer { isApplyingRelationshipAction = false }
 376ŌåÆ
 377ŌåÆ            do {
 378ŌåÆ                let currentRelationship: ActorRelationshipState
 379ŌåÆ                if let relationship {
 380ŌåÆ                    currentRelationship = relationship
 381ŌåÆ                } else if let fetched = try await ActorRelationshipService.fetch(handle: handle, cachePolicy: .networkOnly) {
 382ŌåÆ                    currentRelationship = fetched
 383ŌåÆ                    self.relationship = fetched
 384ŌåÆ                } else {
 385ŌåÆ                    throw ActorRelationshipServiceError.actorNotFound
 386ŌåÆ                }
 387ŌåÆ
 388ŌåÆ                guard !currentRelationship.isViewer else { return }
 389ŌåÆ
 390ŌåÆ                try await ActorRelationshipService.perform(action: action, actorId: currentRelationship.actorId)
 391ŌåÆ                relationship = try await ActorRelationshipService.fetch(handle: handle, cachePolicy: .networkOnly)
 392ŌåÆ            } catch {
 393ŌåÆ                relationshipActionErrorMessage = error.localizedDescription
 394ŌåÆ            }
 395ŌåÆ        }
 396ŌåÆ    }
