 727ŌåÆprivate func plainTextPreview(from html: String) -> String {
 728ŌåÆ    var text = html.replacingOccurrences(of: "<[^>]+>", with: " ", options: .regularExpression)
 729ŌåÆ    text = text.replacingOccurrences(of: "&nbsp;", with: " ")
 730ŌåÆ    text = text.replacingOccurrences(of: "&amp;", with: "&")
 731ŌåÆ    text = text.replacingOccurrences(of: "&lt;", with: "<")
 732ŌåÆ    text = text.replacingOccurrences(of: "&gt;", with: ">")
 733ŌåÆ    text = text.replacingOccurrences(of: "&quot;", with: "\"")
 734ŌåÆ    text = text.replacingOccurrences(of: "&#39;", with: "'")
 735ŌåÆ    text = text.replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
 736ŌåÆ    return text.trimmingCharacters(in: .whitespacesAndNewlines)
 737ŌåÆ}
