1160ŌåÆ                    customEmojiImageUrl: nil,
1161ŌåÆ                    totalCount: 1,
1162ŌåÆ                    viewerHasReacted: true
1163ŌåÆ                )
1164ŌåÆ            )
1165ŌåÆ        }
1166ŌåÆ        reactionsCount = max(0, reactionsCount + (add ? 1 : -1))
