 42ŌåÆprivate func sortReactionGroups(_ groups: [ReactionGroupSnapshot]) -> [ReactionGroupSnapshot] {
 43ŌåÆ    let emojiOrder = Dictionary(uniqueKeysWithValues: supportedReactionEmojis.enumerated().map { ($1, $0) })
