 45ŌåÆ        switch (lhs.emoji, rhs.emoji) {
 46ŌåÆ        case let (.some(leftEmoji), .some(rightEmoji)):
 47ŌåÆ            let leftIndex = emojiOrder[leftEmoji] ?? Int.max
 48ŌåÆ            let rightIndex = emojiOrder[rightEmoji] ?? Int.max
 49ŌåÆ            if leftIndex != rightIndex {
 50ŌåÆ                return leftIndex < rightIndex
 51ŌåÆ            }
 52ŌåÆ            return leftEmoji < rightEmoji
 53ŌåÆ        case (.some, .none):
 54ŌåÆ            return true
 55ŌåÆ        case (.none, .some):
 56ŌåÆ            return false
 57ŌåÆ        case (.none, .none):
 58ŌåÆ            return (lhs.customEmojiName ?? "") < (rhs.customEmojiName ?? "")
 59ŌåÆ        }
 60ŌåÆ    }
 61ŌåÆ}
