 35ŌåÆ    html: String,
 36ŌåÆ    maxLines: Int = Int.MAX_VALUE,
 37ŌåÆ    modifier: Modifier = Modifier,
 38ŌåÆ    fontScale: Float = 1f,
 39ŌåÆ    onMentionClick: ((handle: String) -> Unit)? = null,
 40ŌåÆ    onLinkClick: ((url: String) -> Unit)? = null
