 43ŌåÆ    val isDark = isSystemInDarkTheme()
 44ŌåÆ    val linkColor = if (isDark) Color(0xFF60A5FA) else Color(0xFF2563EB)
 45ŌåÆ    val mentionBg = linkColor.copy(alpha = 0.10f)
 46ŌåÆ    val textColor = MaterialTheme.colorScheme.onSurface
 47ŌåÆ
 48ŌåÆ    val annotatedString = remember(html, linkColor, mentionBg) {
 49ŌåÆ        parseHtmlToAnnotatedString(html, linkColor, mentionBg)
