 66ŌåÆ            annotatedString.getStringAnnotations("MENTION", offset, offset)
 67ŌåÆ                .firstOrNull()?.let { annotation ->
 68ŌåÆ                    val handle = extractHandleFromUrl(annotation.item)
 69ŌåÆ                    if (handle != null && onMentionClick != null) {
 70ŌåÆ                        onMentionClick(handle)
 71ŌåÆ                    } else {
 72ŌåÆ                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 73ŌåÆ                    }
 74ŌåÆ                    return@ClickableText
 75ŌåÆ                }
 76ŌåÆ
 77ŌåÆ            // Then regular links and hashtags
 78ŌåÆ            annotatedString.getStringAnnotations("URL", offset, offset)
 79ŌåÆ                .firstOrNull()?.let { annotation ->
 80ŌåÆ                    if (onLinkClick != null) {
 81ŌåÆ                        onLinkClick(annotation.item)
 82ŌåÆ                    } else {
 83ŌåÆ                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 84ŌåÆ                    }
 85ŌåÆ                }
 86ŌåÆ        }
 87ŌåÆ    )
 88ŌåÆ}
