 51ŌåÆ
 52ŌåÆ    val effectiveFontScale = if (fontScale != 1f) fontScale else LocalFontScale.current
 53ŌåÆ    val baseStyle = MaterialTheme.typography.bodyMedium.copy(color = textColor)
 54ŌåÆ    val scaledStyle = if (effectiveFontScale != 1f) {
