107ŌåÆprivate fun parseHtmlToAnnotatedString(
108ŌåÆ    html: String,
109ŌåÆ    linkColor: Color,
110ŌåÆ    mentionBg: Color
111ŌåÆ): AnnotatedString {
112ŌåÆ    return buildAnnotatedString {
113ŌåÆ        var currentLinkType: LinkType? = null
114ŌåÆ        var hasAnnotation = false
115ŌåÆ        var insideInvisibleSpan = false
116ŌåÆ        var invisibleSpanDepth = 0
117ŌåÆ        var hasContent = false
118ŌåÆ        var isBold = false
119ŌåÆ        var isItalic = false
120ŌåÆ        var isStrikethrough = false
121ŌåÆ        var isCode = false
122ŌåÆ        var isPreformatted = false
123ŌåÆ        var listDepth = 0
124ŌåÆ        var orderedListCounter = 0
125ŌåÆ        var isInList = false
126ŌåÆ        var isBlockquote = false
127ŌåÆ
128ŌåÆ        var pos = 0
129ŌåÆ        val source = html.trim()
130ŌåÆ
131ŌåÆ        while (pos < source.length) {
132ŌåÆ            val tagMatch = TAG_REGEX.find(source, pos)
133ŌåÆ
134ŌåÆ            // Handle text before the next tag (or remaining text if no more tags)
135ŌåÆ            if (tagMatch == null || tagMatch.range.first > pos) {
136ŌåÆ                val textEnd = tagMatch?.range?.first ?: source.length
137ŌåÆ                val rawText = source.substring(pos, textEnd)
138ŌåÆ                val decoded = decodeHtmlEntities(rawText)
139ŌåÆ
140ŌåÆ                if (!insideInvisibleSpan && decoded.isNotEmpty()) {
141ŌåÆ                    val isInterBlockWhitespace = decoded.isBlank() && decoded.contains('\n')
142ŌåÆ                    if (!isInterBlockWhitespace) {
143ŌåÆ                        val styledText = decoded
144ŌåÆ                        val inlineStyle = SpanStyle(
145ŌåÆ                            fontWeight = if (isBold) FontWeight.Bold else null,
146ŌåÆ                            fontStyle = if (isItalic) FontStyle.Italic else null,
147ŌåÆ                            textDecoration = if (isStrikethrough) TextDecoration.LineThrough else null,
148ŌåÆ                            fontFamily = if (isCode || isPreformatted) FontFamily.Monospace else null,
149ŌåÆ                            background = if (isCode && !isPreformatted) Color(0x20808080) else Color.Unspecified
150ŌåÆ                        )
151ŌåÆ
152ŌåÆ                        if (isBold || isItalic || isStrikethrough || isCode || isPreformatted) {
153ŌåÆ                            withStyle(inlineStyle) {
154ŌåÆ                                appendStyledText(this, styledText, currentLinkType, linkColor, mentionBg)
155ŌåÆ                            }
156ŌåÆ                        } else {
157ŌåÆ                            appendStyledText(this, styledText, currentLinkType, linkColor, mentionBg)
158ŌåÆ                        }
159ŌåÆ                        hasContent = true
160ŌåÆ                    }
161ŌåÆ                }
162ŌåÆ
163ŌåÆ                pos = textEnd
164ŌåÆ            }
165ŌåÆ
166ŌåÆ            if (tagMatch != null && tagMatch.range.first == pos) {
167ŌåÆ                val isClosing = tagMatch.groupValues[1] == "/"
168ŌåÆ                val tagName = tagMatch.groupValues[2].lowercase()
169ŌåÆ                val attrString = tagMatch.groupValues[3]
170ŌåÆ
171ŌåÆ                if (!isClosing) {
172ŌåÆ                    val attrs = parseAttributes(attrString)
173ŌåÆ
174ŌåÆ                    when (tagName) {
175ŌåÆ                        "p" -> {
176ŌåÆ                            if (hasContent) append("\n\n")
177ŌåÆ                        }
178ŌåÆ                        "br" -> {
179ŌåÆ                            append("\n")
180ŌåÆ                        }
181ŌåÆ                        "strong", "b" -> {
182ŌåÆ                            isBold = true
183ŌåÆ                        }
184ŌåÆ                        "em", "i" -> {
185ŌåÆ                            isItalic = true
186ŌåÆ                        }
187ŌåÆ                        "del", "s", "strike" -> {
188ŌåÆ                            isStrikethrough = true
189ŌåÆ                        }
190ŌåÆ                        "hr" -> {
191ŌåÆ                            if (hasContent) append("\n")
192ŌåÆ                            append("ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ")
193ŌåÆ                            append("\n")
194ŌåÆ                            hasContent = true
195ŌåÆ                        }
196ŌåÆ                        "code" -> {
197ŌåÆ                            isCode = true
198ŌåÆ                        }
199ŌåÆ                        "pre" -> {
200ŌåÆ                            if (hasContent) append("\n\n")
201ŌåÆ                            isPreformatted = true
202ŌåÆ                        }
203ŌåÆ                        "blockquote" -> {
204ŌåÆ                            if (hasContent) append("\n\n")
205ŌåÆ                            isBlockquote = true
206ŌåÆ                            append("  \u2502 ")
207ŌåÆ                        }
208ŌåÆ                        "ul" -> {
209ŌåÆ                            if (hasContent && listDepth == 0) append("\n")
210ŌåÆ                            listDepth++
211ŌåÆ                            isInList = true
212ŌåÆ                        }
213ŌåÆ                        "ol" -> {
214ŌåÆ                            if (hasContent && listDepth == 0) append("\n")
215ŌåÆ                            listDepth++
216ŌåÆ                            orderedListCounter = 0
217ŌåÆ                            isInList = true
218ŌåÆ                        }
219ŌåÆ                        "li" -> {
220ŌåÆ                            if (hasContent) append("\n")
221ŌåÆ                            val indent = "  ".repeat(listDepth)
222ŌåÆ                            if (orderedListCounter > 0 || tagName == "li") {
223ŌåÆ                                // Check parent ŌĆö simple heuristic: if orderedListCounter was reset, it's unordered
224ŌåÆ                            }
225ŌåÆ                            append("${indent}\u2022 ")
226ŌåÆ                        }
227ŌåÆ                        "h1", "h2", "h3", "h4", "h5", "h6" -> {
228ŌåÆ                            if (hasContent) append("\n\n")
229ŌåÆ                            isBold = true
230ŌåÆ                        }
231ŌåÆ                        "a" -> {
232ŌåÆ                            val classes = attrs["class"] ?: ""
233ŌåÆ                            val href = attrs["href"] ?: ""
234ŌåÆ
235ŌåÆ                            currentLinkType = when {
236ŌåÆ                                "hashtag" in classes -> LinkType.HASHTAG
237ŌåÆ                                "mention" in classes -> LinkType.MENTION
238ŌåÆ                                href.isNotEmpty() -> LinkType.REGULAR
239ŌåÆ                                else -> null
240ŌåÆ                            }
241ŌåÆ
242ŌåÆ                            if (href.isNotEmpty()) {
243ŌåÆ                                val tag = if (currentLinkType == LinkType.MENTION) "MENTION" else "URL"
244ŌåÆ                                pushStringAnnotation(tag, href)
245ŌåÆ                                hasAnnotation = true
246ŌåÆ                            }
247ŌåÆ                        }
248ŌåÆ                        "span" -> {
249ŌåÆ                            val classes = attrs["class"] ?: ""
250ŌåÆ                            if ("invisible" in classes) {
251ŌåÆ                                insideInvisibleSpan = true
252ŌåÆ                                invisibleSpanDepth++
253ŌåÆ                            }
254ŌåÆ                        }
255ŌåÆ                    }
256ŌåÆ                } else {
257ŌåÆ                    when (tagName) {
258ŌåÆ                        "strong", "b" -> {
259ŌåÆ                            isBold = false
260ŌåÆ                        }
261ŌåÆ                        "em", "i" -> {
262ŌåÆ                            isItalic = false
263ŌåÆ                        }
264ŌåÆ                        "del", "s", "strike" -> {
265ŌåÆ                            isStrikethrough = false
266ŌåÆ                        }
267ŌåÆ                        "code" -> {
268ŌåÆ                            isCode = false
269ŌåÆ                        }
270ŌåÆ                        "pre" -> {
271ŌåÆ                            isPreformatted = false
272ŌåÆ                            append("\n")
273ŌåÆ                        }
274ŌåÆ                        "blockquote" -> {
275ŌåÆ                            isBlockquote = false
276ŌåÆ                        }
277ŌåÆ                        "ul", "ol" -> {
278ŌåÆ                            listDepth = maxOf(0, listDepth - 1)
279ŌåÆ                            if (listDepth == 0) {
280ŌåÆ                                isInList = false
281ŌåÆ                                orderedListCounter = 0
282ŌåÆ                            }
283ŌåÆ                        }
284ŌåÆ                        "h1", "h2", "h3", "h4", "h5", "h6" -> {
285ŌåÆ                            isBold = false
286ŌåÆ                            append("\n")
287ŌåÆ                        }
288ŌåÆ                        "a" -> {
289ŌåÆ                            if (hasAnnotation) {
290ŌåÆ                                pop()
291ŌåÆ                                hasAnnotation = false
292ŌåÆ                            }
293ŌåÆ                            currentLinkType = null
294ŌåÆ                        }
295ŌåÆ                        "span" -> {
296ŌåÆ                            if (insideInvisibleSpan) {
297ŌåÆ                                invisibleSpanDepth--
298ŌåÆ                                if (invisibleSpanDepth <= 0) {
299ŌåÆ                                    insideInvisibleSpan = false
300ŌåÆ                                    invisibleSpanDepth = 0
301ŌåÆ                                }
302ŌåÆ                            }
303ŌåÆ                        }
304ŌåÆ                    }
305ŌåÆ                }
306ŌåÆ
307ŌåÆ                pos = tagMatch.range.last + 1
308ŌåÆ            }
309ŌåÆ        }
310ŌåÆ    }
311ŌåÆ}
