361ŌåÆprivate fun decodeHtmlEntities(text: String): String {
362ŌåÆ    return text
363ŌåÆ        .replace("&nbsp;", " ")
364ŌåÆ        .replace("&amp;", "&")
365ŌåÆ        .replace("&lt;", "<")
366ŌåÆ        .replace("&gt;", ">")
367ŌåÆ        .replace("&quot;", "\"")
368ŌåÆ        .replace("&#39;", "'")
369ŌåÆ        .replace("&apos;", "'")
370ŌåÆ}
